import{_ as a,a as d}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as e,o as r,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"使用者頻率限制","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Safety/user-rate-limits.md","filePath":"zh-TW/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),p={name:"zh-TW/Safety/user-rate-limits.md"};function o(s,t,h,n,c,b){return r(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="使用者頻率限制" tabindex="-1">使用者頻率限制 <a class="header-anchor" href="#使用者頻率限制" aria-label="Permalink to &quot;使用者頻率限制&quot;">​</a></h1><p>「使用者頻控」用來限制普通使用者或訪客在首頁上傳檔案的頻率和容量，避免公開上傳入口被大量刷檔。</p><p>這個功能只影響首頁上傳。管理員上傳和 API Token 上傳不受使用者頻控限制。</p><h2 id="功能入口" tabindex="-1">功能入口 <a class="header-anchor" href="#功能入口" aria-label="Permalink to &quot;功能入口&quot;">​</a></h2><p>進入後台後打開：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 安全設定 -&gt; 上傳管理 -&gt; 使用者頻控</span></span></code></pre></div><p><img src="'+a+'" alt="使用者頻控截圖" loading="lazy"></p><h2 id="開啟頻控" tabindex="-1">開啟頻控 <a class="header-anchor" href="#開啟頻控" aria-label="Permalink to &quot;開啟頻控&quot;">​</a></h2><p>打開「啟用頻控」後，系統會依照上傳者 IP 統計最近一段時間內的上傳行為。</p><p>預設設定：</p><table tabindex="0"><thead><tr><th>設定項</th><th>預設值</th><th>說明</th></tr></thead><tbody><tr><td>檢測時間範圍</td><td>1.5 小時</td><td>統計最近多久內的上傳紀錄</td></tr><tr><td>最大上傳檔案數</td><td>20</td><td>檢測時間內最多允許上傳幾個檔案</td></tr><tr><td>單檔大小限制</td><td>20 MB</td><td>單一檔案不能超過這個大小</td></tr><tr><td>累計總容量限制</td><td>200 MB</td><td>檢測時間內總上傳容量不能超過這個值</td></tr></tbody></table><p>例如設定為 1.5 小時、最多 20 個檔案、單檔 20 MB、總容量 200 MB 後，同一個 IP 超過任一限制時，上傳會被擋下。</p><h2 id="排除上傳檔案類型" tabindex="-1">排除上傳檔案類型 <a class="header-anchor" href="#排除上傳檔案類型" aria-label="Permalink to &quot;排除上傳檔案類型&quot;">​</a></h2><p>「排除上傳檔案類型」用來禁止普通使用者或訪客上傳某些類型的檔案。</p><p>目前可以選：</p><table tabindex="0"><thead><tr><th>類型</th><th>說明</th></tr></thead><tbody><tr><td>圖片</td><td>jpg、png、webp、gif 等圖片檔</td></tr><tr><td>影片</td><td>mp4、webm、mov 等影片檔</td></tr><tr><td>音訊</td><td>mp3、flac、wav 等音訊檔</td></tr><tr><td>文件</td><td>pdf、txt、md、docx 等文件</td></tr><tr><td>其他</td><td>不屬於以上類型的檔案，例如 zip、rar、exe、apk</td></tr></tbody></table><p>按鈕預設不選，代表允許上傳。點擊後變成高亮，代表禁止上傳該類型。</p><p>如果勾選「其他」，訪客上傳 zip、rar 這類檔案時會被攔截，並提示不支援此類檔案。</p><h2 id="攔截提示" tabindex="-1">攔截提示 <a class="header-anchor" href="#攔截提示" aria-label="Permalink to &quot;攔截提示&quot;">​</a></h2><p>觸發限制後，使用者會看到對應提示：</p><p><img src="'+d+'" alt="頻繁錯誤提示" loading="lazy"></p><table tabindex="0"><thead><tr><th>情境</th><th>使用者看到的意思</th></tr></thead><tbody><tr><td>單檔過大</td><td>檔案太大，請壓縮後再上傳</td></tr><tr><td>檔案類型被禁止</td><td>不支援上傳該類型檔案，請移除後再試</td></tr><tr><td>上傳太頻繁</td><td>會提示最近上傳太頻繁，並顯示多久後可再試</td></tr><tr><td>累計容量過高</td><td>會提示最近上傳總量過多，並顯示多久後可再試</td></tr></tbody></table><h2 id="什麼時候建議開啟" tabindex="-1">什麼時候建議開啟 <a class="header-anchor" href="#什麼時候建議開啟" aria-label="Permalink to &quot;什麼時候建議開啟&quot;">​</a></h2><p>如果你的首頁上傳對外開放，建議開啟使用者頻控。</p><p>常見情境：</p><ul><li>擔心有人用腳本連續上傳大量檔案。</li><li>想限制訪客上傳太大的檔案。</li><li>只希望一般使用者上傳圖片，不希望上傳壓縮檔、安裝檔。</li><li>想保留公開上傳能力，但控制伺服器資源消耗。</li></ul><p>如果站台只給自己用，或已經只允許管理員上傳，可以保持關閉。</p>',27)])])}const f=e(p,[["render",o]]);export{_ as __pageData,f as default};
